 3→import (
 4→	"fmt"
 5→
 6→	"golang.org/x/crypto/bcrypt"
 7→)
 8→
 9→// HashPassword returns a bcrypt hash of the given password.
10→func HashPassword(password string) (string, error) {
11→	hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
12→	if err != nil {
13→		return "", fmt.Errorf("auth: hash password: %w", err)
14→	}
15→	return string(hash), nil
16→}
17→
18→// CheckPassword compares a bcrypt hash with a plaintext password.
19→// Returns nil on success or an error if they don't match.
20→func CheckPassword(hash, password string) error {
21→	if err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(password)); err != nil {
22→		return fmt.Errorf("auth: check password: %w", err)
23→	}
24→	return nil
25→}
